33	/// Handle returned by [`TrayHandle::spawn`]; keeps the tray alive for the process lifetime.
34	pub struct TrayHandle {
35	    /// Set to true by the tray "Open Config" action; cleared by the eframe loop.
36	    pub open_window: Arc<AtomicBool>,
37	    _thread: std::thread::JoinHandle<()>,
38	}
