59	    /// Append a log line, dropping the oldest entry when the cap is reached.
60	    pub fn add_log_line(&mut self, line: String) {
61	        if self.log_lines.len() >= MAX_LOG_LINES {
62	            self.log_lines.remove(0);
63	        }
64	        self.log_lines.push(line);
