67	    /// Copy config-derived fields from a loaded `Config` into this app state.
68	    ///
69	    /// `threshold_pct` is rounded (not truncated) and clamped to 0–100 to guard
70	    /// against out-of-range values in hand-edited config files.
71	    pub fn apply_from_config(&mut self, cfg: &Config) {
72	        self.threshold_pct = (cfg.stt.confidence_threshold * 100.0)
73	            .round()
74	            .clamp(0.0, 100.0) as u8;
75	        self.input_device = cfg.audio.device.clone();
76	        self.ptt_binding = cfg.ptt.key.clone();
77	    }
